#include <iostream>
#include <string>
#include <cctype>
using namespace std;

int main() {
    string s = "Hello World 123";

    // Index-based iteration
    cout << "Characters: ";
    for (int i = 0; i < (int)s.length(); i++) {
        cout << s[i];
    }
    cout << endl;

    // Range-based (read-only)
    int vowels = 0, digits = 0, spaces = 0;
    for (char c : s) {
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u' ||
            c == 'A' || c == 'E' || c == 'I' || c == 'O' || c == 'U') vowels++;
        if (isdigit(c)) digits++;
        if (isspace(c)) spaces++;
    }
    cout << "Vowels: " << vowels << ", Digits: " << digits << ", Spaces: " << spaces << endl;

    // Range-based (modify by reference)
    string upper = s;
    for (char &c : upper) {
        c = toupper(c);
    }
    cout << "Uppercase: " << upper << endl;

    // Convert using char arithmetic
    string lower = s;
    for (char &c : lower) {
        if (c >= 'A' && c <= 'Z') c += 32;
    }
    cout << "Lowercase: " << lower << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

// Manual reverse using two pointers
string manualReverse(string s) {
    int left = 0, right = s.length() - 1;
    while (left < right) {
        swap(s[left], s[right]);
        left++;
        right--;
    }
    return s;
}

bool isPalindrome(string s) {
    int left = 0, right = s.length() - 1;
    while (left < right) {
        if (s[left] != s[right]) return false;
        left++;
        right--;
    }
    return true;
}

int main() {
    string s1 = "Hello";
    cout << "Manual reverse: " << manualReverse(s1) << endl;

    // STL reverse (modifies in place)
    string s2 = "abcdef";
    reverse(s2.begin(), s2.end());
    cout << "STL reverse: " << s2 << endl;

    // Palindrome check
    string words[] = {"racecar", "hello", "madam", "level", "cpp"};
    for (string &w : words) {
        cout << w << ": " << (isPalindrome(w) ? "Palindrome" : "Not palindrome") << endl;
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

bool areAnagrams(string s1, string s2) {
    if (s1.length() != s2.length()) return false;

    int freq[26] = {0};
    for (char c : s1) freq[c - 'a']++;
    for (char c : s2) freq[c - 'a']--;

    for (int i = 0; i < 26; i++) {
        if (freq[i] != 0) return false;
    }
    return true;
}

int main() {
    string pairs[][2] = {
        {"listen", "silent"},
        {"hello", "world"},
        {"anagram", "nagaram"},
        {"rat", "tar"}
    };

    for (auto &p : pairs) {
        cout << "\"" << p[0] << "\" and \"" << p[1] << "\": ";
        cout << (areAnagrams(p[0], p[1]) ? "Anagrams" : "Not anagrams") << endl;
    }

    return 0;
}

