int main() {
    string s;
    getline(cin, s);
    vector<string> words;
    string word = "";
    for (int i = 0; i <= (int)s.length(); i++) {
        if (i == (int)s.length() || s[i] == ' ') {
            if (!word.empty()) {
                words.push_back(word);
                word = "";
            }
        } else {
            word += s[i];
        }
    }
    for (int i = words.size() - 1; i >= 0; i--) {
        cout << words[i];
        if (i > 0) cout << " ";
    }
    cout << endl;
    return 0;
}

#include <iostream>
#include <string>
using namespace std;
bool isPalindrome(string s) {
    int l = 0, r = s.length() - 1;
    while (l < r) {
        if (s[l] != s[r]) return false;
        l++; r--;
    }
    return true;
}
int main() {
    string s;
    cin >> s;
    string longest = "";
    for (int i = 0; i < (int)s.length(); i++) {
        for (int len = 1; len <= (int)s.length() - i; len++) {
            string sub = s.substr(i, len);
            if (isPalindrome(sub) && (int)sub.length() > (int)longest.length()) {
                longest = sub;
            }
        }
    }
    cout << longest << endl;
    return 0;
}

#include <iostream>
#include <string>
using namespace std;
int main() {
    string s;
    cin >> s;
    if (s.empty()) {
        cout << s << endl;
        return 0;
    }
    string compressed = "";
    int count = 1;
    for (int i = 1; i <= (int)s.length(); i++) {
        if (i < (int)s.length() && s[i] == s[i - 1]) {
            count++;
        } else {
            compressed += s[i - 1];
            compressed += to_string(count);
            count = 1;
        }
    }
    if ((int)compressed.length() >= (int)s.length()) {
        cout << s << endl;
    } else {
        cout << compressed << endl;
    }
    return 0;
}
